},
"project_id": {
  "type": "string",
  "minLength": 1,
  "description": "横断分類用project identifier。物理top-levelを決めず、閾値超過時だけsecondary partitionに使う"
},
"domain": {
  "type": "string",
  "minLength": 1,
  "description": "横断分類用domain。1 leafが200件を超えた場合の第一partition key"
},
"tags": {
  "type": "array",
  "items": {
    "type": "string",
    "minLength": 1
  },
  "uniqueItems": true,
  "description": "物理配置から独立した横断検索タグ"
},
"priority": {
  "type": [
    "string",
    "null"
  ],
  "description": "tracker/Projectsへ投影可能なrepo-local priority。nullは未設定"
},
"start_date": {
  "type": [
    "string",
    "null"
  ],
  "format": "date"
},
"target_date": {
  "type": [
    "string",
    "null"
  ],
  "format": "date"
},
"iteration": {
  "type": [
    "string",
    "null"
  ],
  "description": "Projects iteration title等へ写像する安定した人間可読値"
},
"title": {
  "type": "string",
  "minLength": 1
},
"owners": {
  "type": "array",
  "items": {
    "type": "string",
    "minLength": 1
  },
  "description": "成果物の更新責任者"
},
"created_at": {
  "type": "string",
  "format": "date-time"
},
"updated_at": {
  "type": "string",
  "format": "date-time",
  "description": "id + updated_at がGitHub双方向同期(要件C4)の競合解決キー"
},
"status": {
  "type": "string",
  "enum": [
    "draft",
    "active",
    "blocked",
    "done",
    "closed",
    "tombstoned"
  ],
  "description": "全artifact共通workflow state。GitHub Issue openはactive、closeはclosedへ写像し、delete相当はtombstonedで物理削除しない"
},
"closed_at": {
  "type": [
    "string",
    "null"
  ],
  "format": "date-time",
  "description": "status=closed|tombstoned に遷移した時刻。close/delete のtombstone双方向伝播(要件C12)がこの時刻を記録する"
},
"depends_on": {
  "type": "array",
  "items": {
    "type": "string"
  },
  "description": "依存先ノードid配列。ready-set算出(要件C8)の入力。feature ノード間の機能間依存もこのフィールドを流用する (新フィールド不要・MM-01)"
},
"related_nodes": {
  "type": "array",
  "items": {
    "type": "string"
  },
  "uniqueItems": true,
  "description": "順序依存を持たない関連ノード参照"
},
"resource_scope": {
  "type": "array",
  "items": {
    "type": "string",
    "pattern": "^(?!/)(?!.*(?:^|/)\\.\\.(?:/|$)).+$"
  },
  "description": "touches: このノードが触るファイル/ディレクトリパス配列。既定はディレクトリ単位、ノードがファイル単位を明示した場合はファイル単位を優先し、双方混在時は広い方(ディレクトリ単位)へフォールバックする。並列バッチのresource_scope重複回避(要件C10)の土台"
},
"purpose": {
  "type": [
    "string",
    "null"
  ],
  "description": "feature ノードがなぜ必要かの説明 (JTBD/価値)。artifact_kind=feature のとき非null必須、他kindはnull (MM-01)"
},
"goal": {
  "type": [
    "string",
    "null"
  ],
  "description": "feature ノードが達成する到達状態。旧 目標+ゴールの語彙を1本に統合した表現。artifact_kind=feature のとき非null必須、他kindはnull (MM-01)。program全体のgoalはgoal-spec.jsonが正本で、本フィールドは機能単位に閉じる"
},
"scope_in": {
  "type": "array",
  "items": {
    "type": "string",
    "minLength": 1
  },
  "description": "feature ノードのスコープ内。artifact_kind=feature のとき1件以上必須、他kindは空配列 (MM-01)"
},
"scope_out": {
  "type": "array",
  "items": {
    "type": "string",
    "minLength": 1
  },
  "description": "feature ノードのスコープ外。artifact_kind=feature のとき1件以上必須、他kindは空配列 (MM-01)"
},
"acceptance": {
  "type": "array",
  "items": {
    "type": "string",
    "minLength": 1
  },
  "description": "feature ノードが確実に実行したい観測可能な二値条件。artifact_kind=feature のとき1件以上必須、他kindは空配列 (MM-01)"
},
"architecture_refs": {
  "type": "array",
  "items": {
    "type": "string",
    "minLength": 1
  },
  "uniqueItems": true,
  "description": "feature ノードが参照する architecture ノードの graph_node_id 配列。artifact_kind=feature のとき1件以上必須、他kindは空配列 (MM-01)。system-spec-harness由来のarchitectureはlineage参照のみで複製しない (MM-12)"
},
"parent_feature": {
  "type": [
    "string",
    "null"
  ],
  "description": "task ノードが属する feature ノードの graph_node_id。artifact_kind=task かつ feature 由来のときのみ非null (feature文脈を持たない単発taskはnull可)。artifact_kind!=task では常にnull。順序依存のないrelated_nodesや複数依存を表すdepends_onとは別概念の単一親参照 (MM-03)"
},
"feature_package_id": {
  "type": ["string", "null"],
  "pattern": "^feature-package/[A-Za-z0-9._/-]+$",
  "description": "system-dev-plannerが1 featureから生成したexact 13 task package identity。feature由来taskは非null、他artifactと単発taskはnull"
},
"phase_ref": {
  "type": ["string", "null"],
  "enum": [null, "P01", "P02", "P03", "P04", "P05", "P06", "P07", "P08", "P09", "P10", "P11", "P12", "P13"],
  "description": "feature execution package内の一意phase slot。P01..P13各1件。feature由来task以外はnull"
},
"file_path": {
  "type": "string",
  "pattern": "^(issues|tasks|specs|architecture|features|docs)/.+\\.md$",
  "description": "全artifactが持つ正規root配下の人間可読Markdownへの参照。graph_node_idは不変、file_pathはrouting policyとpartition状態から再計算可能な派生値。feature は features/ 配下 (MM-02)"
},
"template_id": {
  "type": "string",
  "enum": [
    "issue",
    "task",
    "document",
    "specification",
    "architecture",
    "feature"
  ],
  "description": "artifact_kindから自動選択した基底テンプレート"
},
"template_version": {
  "type": "string",
  "pattern": "^[0-9]+\\.[0-9]+\\.[0-9]+$",
  "description": "生成時に使用したテンプレート契約版。正本更新時は既存文書を全書換せずmigration previewへ使う"
},
"confirmation_status": {
  "type": "string",
  "enum": [
    "draft",
    "confirmed",
    "superseded"
  ],
  "description": "内容確定状態。system plan入力はspecification/architectureがconfirmedであることを要求する"
},
"evaluation_status": {
  "type": "string",
  "enum": [
    "pending",
    "pass",
    "fail",
    "stale"
  ],
  "description": "独立評価状態。C14/C15/C04はpass以外をIssue起票・推薦・実装handoff対象にしない"
},
"confirmation_evidence": {
  "type": "object",
  "required": [
    "evaluator",
    "evidence_ref",
    "evaluated_digest"
  ],
  "properties": {
    "evaluator": {
      "type": [
        "string",
        "null"
      ]
    },
    "evidence_ref": {
      "type": [
        "string",
        "null"
      ]
    },
    "evaluated_digest": {
      "type": [
        "string",
        "null"
      ],
      "pattern": "^[a-f0-9]{64}$"
    }
  },
  "additionalProperties": false,
  "description": "confirmation/evaluationを同一artifact digestへpinしstale PASSを拒否する"
},
"source_lineage": {
  "type": "object",
  "required": [
    "origin_kind",
    "source_plugin",
    "source_path",
    "source_version",
    "source_digest",
    "imported_at"
  ],
  "properties": {
